// v19.3: solar=0 (noc) -> MaxDischargePower=0 blokuje DC bus standby loss
// Victron transfer relay zajisti grid passthrough i s MaxDischargePower=0
var currentSolar = rawSolar > 10 ? Math.max(50, rawSolar) : 0;

// Grid bias kompenzuje inverter standby (~130W)
var gridBias = config.setrit_grid_bias_w || 150;

// v25.55e: Dynamic PSP ÔÇö grid pokryje deficit (consumption - solar)
// rozdil = production - consumption (negative = spotreba > vyroba)
