    max_feed_in_power:         config.max_feed_in_w || 7600,
    prevent_feedback:          0
};
msg.mode = "setrit";
msg.blockDischarge = true;

node.status({fill:"yellow", shape:"dot", text:"SETRIT SOC:" + liveSoc + "% mS:" + effectiveMinSoc + "% PSP:" + dynamicPSP + "(+" + chargeBias + ") disch:" + (currentSolar > 0 ? currentSolar : 0)});

global.set("energy_arbiter", {
