// LAW 5.1: SOC < MSS Ôćĺ stop (0A)
if(soc<MSS){node.status({fill:"red",shape:"ring",text:"SOC "+soc+"%<"+MSS+"%Ôćĺ0A"});msg.payload=0;return msg;}

var hi=soc>=99;
var drain=soc>=SDT;
