    if(ghc>=2){tA=curA-1;global.set("solar_corr_ghc",0);zone="GRID:"+Math.round(gridW)+"W>"+gMax+"W";}
    else{zone="GW:"+Math.round(gridW)+"W(wait)";}
  }
  // DRAIN (SOC>=95%): battery MUST discharge
  else if(drain){
