  }else{global.set("solar_corr_stop_cnt",0);}
  if(tA>16)tA=16;
  node.status({fill:tA>0?"green":"red",shape:"dot",
    text:tA+"A("+zone+" b:"+Math.round(bW)+"W g:"+Math.round(gridW)+"W n:"+curA+"A SOC:"+soc+"%)"});
